import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const d="/docs/modules/porta-sampler.png",m=JSON.parse('{"title":"PortaSampler","description":"","frontmatter":{},"headers":[],"relativePath":"modules/porta-sampler.md","filePath":"modules/porta-sampler.md"}'),s={name:"modules/porta-sampler.md"};function n(i,t,l,h,c,p){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="portasampler" tabindex="-1">PortaSampler <a class="header-anchor" href="#portasampler" aria-label="Permalink to &quot;PortaSampler&quot;">​</a></h1><p><strong>Category:</strong> Sound Sources</p><p>8-slot sample recorder and player. Records sounds from the audio input using threshold detection with pre-roll transient capture, then plays them back from gate triggers, MIDI notes, or hardware buttons. Each slot supports up to 3 velocity layers. Three modes: one-shot, loop, velocity-layer. Kits can be saved to and loaded from the SD card. Auto-mapped across 3 hardware banks for record, mix, and trim/trigger control.</p><img src="'+d+'" alt="porta-sampler module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>audioIn</strong> (audio)</td><td>Audio input for recording. Connect from a Piezo Input, Stereo In, or any audio source.</td></tr><tr><td><strong>gate1</strong>..<strong>gate8</strong></td><td>Trigger gates for slots 1-8. Rising edge starts playback. Gates 5-8 are hidden by default; show them with <code>show_gates_5_8</code>.</td></tr><tr><td><strong>pitch_cv</strong></td><td>Pitch CV affecting all voices. 0.5 = unity, higher = faster playback.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>mixL</strong> (audio)</td><td>Left main mix.</td></tr><tr><td><strong>mixR</strong> (audio)</td><td>Right main mix.</td></tr><tr><td><strong>auxL</strong> (audio)</td><td>Left aux send.</td></tr><tr><td><strong>auxR</strong> (audio)</td><td>Right aux send.</td></tr></tbody></table><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>bank</code></td><td>1</td><td>Hardware bank assignment (auto-claimed). PortaSampler consumes 3 consecutive banks.</td></tr><tr><td><code>threshold</code></td><td>0.47</td><td>Recording threshold 0-1. Recording auto-starts when the input crosses this and auto-stops when it falls back below.</td></tr><tr><td><code>max_length</code></td><td>0.6</td><td>Maximum recording duration per slot, as a fraction of the available sample pool.</td></tr><tr><td><code>master_level</code></td><td>0.8</td><td>Master output level.</td></tr><tr><td><code>kit_folder</code></td><td>&quot;&quot;</td><td>SD folder used for kit save/load.</td></tr><tr><td><code>show_gates_5_8</code></td><td>false</td><td>Show gate inputs 5-8 in the patcher UI.</td></tr></tbody></table><h2 id="hardware-mapping" tabindex="-1">Hardware Mapping <a class="header-anchor" href="#hardware-mapping" aria-label="Permalink to &quot;Hardware Mapping&quot;">​</a></h2><p>PortaSampler claims <strong>3 consecutive banks</strong>:</p><ul><li><strong>Bank 1 -- Record:</strong> Pot1 = threshold, Pot2 = length, Pot3 = mode, Pot4 = layer level. Btn1 = arm, Btn2 = reverse, Btn3 = previous slot, Btn4 = next slot.</li><li><strong>Bank 2 -- Mix:</strong> Pot1 = volume, Pot2 = pitch, Pot3 = pan, Pot4 = aux send. Btn1-4 = mute slots 1-4.</li><li><strong>Bank 3 -- Trim / Trigger:</strong> Pot1 = start, Pot2 = end. Btn1-4 = manually trigger slots 1-4.</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Connect a Piezo Input or Stereo In to the <code>audioIn</code> input. Switch to Bank 1, set the threshold with Pot1, and press Btn1 to arm. Make a sound and recording starts automatically when the input crosses the threshold, then stops when it dies away. Navigate slots with Btn3 / Btn4. Use Bank 3 buttons to trigger slots manually, or Bank 2 mute buttons to silence them. Kits can be saved and loaded over the serial console using the <code>PSSAVE</code> and <code>PSLOAD</code> commands. Slots 5-8 can be triggered via gate inputs (enable <code>show_gates_5_8</code>) or MIDI notes 40-43.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',16)])])}const g=e(s,[["render",n]]);export{m as __pageData,g as default};
